export const toolFaqIt: Record<string, FAQItem[]> = {
  "merge": [
    { question: "Come unisco più PDF in un unico file?", answer: "Aggiungi i file PDF che vuoi combinare, quindi trascinali nell'ordine che preferisci. Una volta sistemati, lo strumento li unisce in un unico documento mantenendo i font, il layout e la formattazione originali di ogni file. Scarica subito il risultato unito." },
    { question: "Posso riordinare i PDF prima di unirli?", answer: "Sì. Prima di combinarli, puoi trascinare ogni file nella sequenza che preferisci, così il documento finale rispetta esattamente l'ordine desiderato. È comodo quando consolidi capitoli, fatture o contratti che devono comparire in una disposizione specifica." },
    { question: "C'è un limite al numero di PDF che posso combinare?", answer: "Puoi unire tutti i file PDF che ti servono in un unico documento. Poiché tutto avviene localmente nel tuo browser usando la memoria del tuo dispositivo, i batch molto grandi dipendono dalle risorse disponibili sul tuo computer anziché da un limite fisso del server." },
    { question: "I miei file vengono caricati da qualche parte quando li unisco?", answer: "No. Tutta l'unione avviene direttamente nel tuo browser, quindi i tuoi PDF non lasciano mai il dispositivo né passano da un server. In questo modo i documenti sensibili come contratti e report finanziari restano completamente privati e riservati durante tutto il processo." },
    { question: "Lo strumento Unisci PDF è gratuito?", answer: "Completamente gratuito, senza registrazione né account. Puoi combinare PDF illimitati ogni volta che vuoi senza alcun costo, e non viene aggiunta nessuna filigrana al documento unito." },
  ],
  "split": [
    { question: "Come divido un PDF in file separati?", answer: "Carica il tuo PDF e scegli un metodo di divisione: intervalli di pagine personalizzati, un numero fisso di pagine o una divisione ogni N pagine. Lo strumento suddivide quindi il documento in file più piccoli all'istante, ciascuno con la stessa qualità di testo, immagini e formattazione originali." },
    { question: "Quali metodi di divisione supporta questo strumento?", answer: "Puoi dividere per intervalli di pagine personalizzati per estrarre sezioni specifiche, per un numero fisso di pagine per file oppure ogni N pagine. Questa flessibilità ti permette di suddividere un report lungo in capitoli o di estrarre esattamente le pagine che ti servono." },
    { question: "La divisione può aiutarmi a rispettare i limiti di dimensione degli allegati email?", answer: "Sì. Suddividere un PDF di grandi dimensioni in file più piccoli è un modo comune per far rientrare i documenti nei limiti di dimensione delle email o dei caricamenti. Dividi il file in parti gestibili, quindi invia ogni parte separatamente senza perdere qualità." },
    { question: "La divisione riduce la qualità del mio PDF?", answer: "No. Ogni file risultante conserva la stessa nitidezza del testo, le stesse immagini e la stessa formattazione del PDF di origine. L'operazione di divisione separa semplicemente le pagine senza ricomprimerle, quindi ogni output corrisponde alla qualità del documento originale." },
    { question: "I miei documenti vengono caricati quando divido un PDF?", answer: "Mai. L'intera divisione avviene all'interno del tuo browser, quindi il file resta sul tuo dispositivo per tutto il tempo. Nulla viene inviato a un server, il che mantiene il materiale riservato o sensibile completamente privato." },
  ],
  "delete-pages": [
    { question: "Come elimino pagine da un PDF?", answer: "Seleziona le pagine che vuoi rimuovere e lo strumento crea un nuovo PDF senza di esse, lasciando intatto il resto del contenuto. Puoi rimuovere una singola pagina, più pagine o interi intervalli in un'unica operazione, quindi scaricare il file ripulito." },
    { question: "Posso rimuovere più pagine contemporaneamente?", answer: "Sì. Puoi eliminare pagine singole, più pagine sparse o interi intervalli di pagine in un'unica azione. Questo rende rapido rimuovere pagine vuote, sezioni superflue o materiale riservato prima di condividere il documento." },
    { question: "Eliminare pagine modifica il mio file originale?", answer: "No. Il processo non è distruttivo, quindi il tuo PDF di origine resta intatto finché non scarichi la versione modificata. Lavori sempre su una copia, il che significa che puoi sperimentare liberamente senza rischiare il documento originale." },
    { question: "Rimuovere pagine influisce sulla qualità del resto?", answer: "Per niente. Ogni pagina rimanente mantiene la formattazione, le immagini e la qualità del testo originali. L'eliminazione delle pagine rimuove solo quelle che selezioni, lasciando il contenuto restante esattamente come appariva nel PDF di origine." },
    { question: "È privato eliminare pagine da documenti sensibili?", answer: "Sì. Tutta l'elaborazione avviene localmente nel tuo browser, quindi i file che contengono informazioni riservate non vengono mai caricati su alcun server. Questo rende sicuro rimuovere pagine private da contratti, report o documenti scansionati sul tuo dispositivo." },
  ],
  "extract-pages": [
    { question: "Come estraggo pagine specifiche da un PDF?", answer: "Scegli le pagine che desideri e lo strumento crea un nuovo PDF contenente solo quelle pagine. Puoi estrarre una singola pagina, più pagine o interi intervalli, quindi scaricare un documento mirato che include esattamente il contenuto selezionato." },
    { question: "Le pagine estratte mantengono il testo ricercabile e selezionabile?", answer: "Sì. Lo strumento conserva i font, il layout, le immagini e il testo originali, quindi le pagine estratte appaiono identiche all'originale. Il testo resta completamente ricercabile e selezionabile, il che è utile quando estrai capitoli o sezioni di report da riutilizzare in seguito." },
    { question: "Qual è la differenza tra estrarre e dividere le pagine?", answer: "L'estrazione raccoglie solo le pagine che scegli in un unico nuovo documento, ideale per creare un file mirato da pagine sparse. La divisione suddivide un PDF in più file separati. Usa l'estrazione quando vuoi un'unica raccolta personalizzata di pagine specifiche." },
    { question: "Posso estrarre pagine non consecutive in un unico documento?", answer: "Sì. Puoi selezionare pagine singole da parti diverse del PDF così come intervalli continui, e vengono combinate in un unico nuovo file. È perfetto per assemblare un documento personalizzato con solo le sezioni rilevanti." },
    { question: "I miei file sono al sicuro quando estraggo le pagine?", answer: "Assolutamente. L'estrazione avviene interamente nel tuo browser, quindi i tuoi documenti non lasciano mai il dispositivo né vengono caricati da nessuna parte. Puoi estrarre pagine da report riservati o libri di testo in tutta sicurezza, sapendo che nulla viene inviato a un server." },
  ],
  "reorder": [
    { question: "Come riorganizzo le pagine in un PDF?", answer: "Apri il tuo PDF per vedere le anteprime in miniatura di ogni pagina, quindi trascina qualsiasi pagina in una nuova posizione. Il layout visivo rende facile individuare e spostare le pagine giuste, e puoi visualizzare in anteprima il nuovo ordine prima di scaricare." },
    { question: "Posso spostare più pagine insieme quando riordino?", answer: "Sì. Puoi trascinare le pagine una alla volta oppure selezionare più pagine e spostarle come gruppo. Questo accelera le riorganizzazioni più grandi, come spostare un'intera sezione di un report in un altro punto del documento." },
    { question: "Lo strumento mostra le miniature delle pagine mentre riordino?", answer: "Sì. Ogni pagina appare come anteprima in miniatura, così puoi vedere chiaramente cosa stai spostando e confermare visivamente la disposizione. Questo rende molto più facile correggere una scansione in ordine errato o ristrutturare i contenuti rispetto al lavorare solo con i numeri di pagina." },
    { question: "Riordinare le pagine riduce la qualità del documento?", answer: "No. Riorganizzare le pagine preserva tutta la formattazione, le immagini e la qualità del testo dell'originale. Lo strumento modifica solo la sequenza delle pagine, quindi ogni pagina mantiene la sua piena nitidezza e resta ricercabile nel documento riordinato." },
    { question: "Il riordino avviene in modo privato nel mio browser?", answer: "Sì. L'intero processo di trascinamento avviene localmente sul tuo dispositivo, senza che nessun file venga caricato su alcun server. I tuoi documenti restano privati, il che rende sicuro riorganizzare PDF sensibili o riservati." },
  ],
  "rotate": [
    { question: "Come ruoto le pagine in un PDF?", answer: "Scegli le pagine che vuoi girare e seleziona una rotazione di 90, 180 o 270 gradi. Puoi ruotare tutto in una volta oppure correggere solo le pagine con l'orientamento sbagliato, quindi scaricare immediatamente il documento corretto." },
    { question: "Posso ruotare solo una pagina invece dell'intero PDF?", answer: "Sì. Lo strumento ti permette di ruotare pagine specifiche singolarmente, così puoi correggere solo quelle acquisite con l'angolazione sbagliata lasciando ogni altra pagina esattamente com'era. È ideale per correggere errori di scansione isolati." },
    { question: "Quali angoli di rotazione sono disponibili?", answer: "Puoi ruotare le pagine di 90, 180 o 270 gradi. Questi coprono le correzioni di orientamento più comuni, sia che una pagina scansionata risulti di lato, capovolta, o debba essere girata per soddisfare un requisito specifico di visualizzazione o stampa." },
    { question: "La rotazione influisce sulla qualità del testo o delle immagini?", answer: "No. La rotazione preserva tutta la qualità del contenuto, incluse testo, immagini e formattazione. Il testo ruotato resta ricercabile e selezionabile, quindi il documento mantiene la piena funzionalità e appare nitido come prima, solo con l'angolazione corretta." },
    { question: "I miei file vengono caricati quando ruoto le pagine?", answer: "No. La rotazione avviene istantaneamente all'interno del tuo browser, quindi i tuoi documenti non lasciano mai il dispositivo. Questa elaborazione locale mantiene i documenti scansionati o i file privati completamente riservati mentre ne correggi l'orientamento." },
  ],
  "insert-blank": [
    { question: "Come inserisco pagine vuote in un PDF?", answer: "Specifica dove vuoi che vadano le pagine vuote e quante aggiungerne. Lo strumento inserisce pagine vuote all'inizio, alla fine o tra qualsiasi pagina esistente, quindi ti permette di scaricare subito il documento aggiornato." },
    { question: "Dove posso aggiungere pagine vuote nel mio documento?", answer: "Puoi inserirle all'inizio, alla fine o tra due pagine esistenti qualsiasi. Basta scegliere la posizione esatta e il numero di pagine da aggiungere, dandoti il pieno controllo su dove compare il nuovo spazio." },
    { question: "Quale dimensione avranno le pagine vuote inserite?", answer: "Le pagine vuote corrispondono automaticamente alla dimensione e all'orientamento delle pagine esistenti del documento. Questo mantiene il file coerente per la stampa o la rilegatura, così lo spazio aggiunto si integra perfettamente con il resto del tuo PDF." },
    { question: "Perché dovrei aggiungere pagine vuote a un PDF?", answer: "I motivi più comuni includono lasciare spazio per note scritte a mano, creare interruzioni di pagina per la stampa, preparare un documento per la rilegatura o riservare spazi segnaposto per contenuti da aggiungere in seguito. Lo strumento rende rapido configurare tutte queste operazioni." },
    { question: "Inserire pagine vuote è gratuito e privato?", answer: "Sì su entrambi i fronti. Lo strumento è gratuito senza registrazione e tutta l'elaborazione avviene localmente nel tuo browser. Il tuo file non viene mai caricato su un server, quindi il documento resta privato dall'inizio alla fine." },
  ],
  "duplicate-pages": [
    { question: "Come duplico le pagine all'interno di un PDF?", answer: "Seleziona le pagine che vuoi copiare e scegli dove devono andare i duplicati. Lo strumento crea copie esatte e le posiziona nel punto che specifichi, quindi ti permette di scaricare immediatamente il documento aggiornato." },
    { question: "Posso duplicare più di una pagina alla volta?", answer: "Sì. Puoi copiare una singola pagina o più pagine in un'unica operazione e inserire i duplicati ovunque nel documento. È comodo per ripetere più volte un modulo compilabile o una pagina template senza copiare e incollare manualmente." },
    { question: "Le pagine duplicate sono copie esatte degli originali?", answer: "Sì. Ogni duplicato conserva tutta la formattazione, le immagini, il testo e gli elementi visivi della pagina di origine, quindi la copia è identica nell'aspetto e nella funzionalità. Nulla viene perso o alterato durante la duplicazione." },
    { question: "Dove posso collocare le pagine duplicate?", answer: "Puoi posizionare le copie in qualsiasi punto del documento, non solo accanto agli originali. Questo ti permette di creare un PDF con moduli, template o pagine di backup ripetuti, disposti esattamente dove ti servono." },
    { question: "Duplicare le pagine mantiene i miei file privati?", answer: "Sì. L'intera duplicazione avviene nel tuo browser, quindi i tuoi documenti non lasciano mai il dispositivo né raggiungono un server. Puoi copiare pagine da moduli o template sensibili con completa privacy e sicurezza." },
  ],
  "reverse-order": [
    { question: "Come faccio a invertire l'ordine delle pagine nel mio PDF?", answer: "Carica il tuo PDF e lo strumento capovolge istantaneamente l'intera sequenza delle pagine, così l'ultima pagina diventa la prima e la prima diventa l'ultima. Non c'è nulla da configurare. Una volta invertito, puoi scaricare subito il nuovo PDF." },
    { question: "Invertire l'ordine modificherà il contenuto o la qualità delle mie pagine?", answer: "No. Cambia solo la sequenza delle pagine. Ogni pagina mantiene esattamente il testo, le immagini, la formattazione e la risoluzione originali. Le pagine in sé restano intatte, semplicemente riordinate dall'ultima alla prima, quindi la qualità rimane identica al file di origine." },
    { question: "Posso correggere un PDF scansionato al contrario con questo strumento?", answer: "Sì, è un uso molto comune. Se il tuo scanner ha acquisito le pagine in ordine inverso, questo strumento capovolge l'intera sequenza riportandola al corretto ordine dalla prima all'ultima con un solo clic, evitandoti di riordinare manualmente ogni pagina." },
    { question: "Lo strumento Inverti Ordine Pagine è gratuito?", answer: "Completamente gratuito e senza registrazione. Puoi invertire quanti PDF vuoi senza alcun costo. Non vengono aggiunte filigrane e non devi creare account prima di scaricare il documento invertito." },
    { question: "I miei file sono privati quando inverto l'ordine delle pagine?", answer: "Sì. Tutta l'elaborazione avviene localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su alcun server. Il documento rimane interamente sul tuo dispositivo durante tutta l'inversione, mantenendo i file riservati completamente privati." },
  ],
  "split-by-size": [
    { question: "Come funziona la suddivisione di un PDF per dimensione del file?", answer: "Imposti un limite massimo di dimensione e lo strumento analizza il tuo PDF dividendolo in punti sensati, così ogni file risultante resta sotto quel limite. Carica il documento, scegli la dimensione desiderata e scarica i file più piccoli generati." },
    { question: "Quali unità di dimensione posso impostare come limite?", answer: "Puoi specificare il massimo in KB, MB o GB, ottenendo un controllo preciso sulle dimensioni in uscita. Questo rende facile rispettare i limiti degli allegati email, le restrizioni di archiviazione cloud o qualsiasi requisito specifico di dimensione file di una piattaforma per i tuoi file suddivisi." },
    { question: "Posso scaricare tutti i file suddivisi in una volta sola?", answer: "Sì. Dopo la suddivisione puoi prelevare ogni file risultante singolarmente oppure scaricarli tutti insieme in un unico archivio ZIP, comodo quando il tuo PDF viene diviso in più parti." },
    { question: "Ogni file suddiviso manterrà la stessa qualità dell'originale?", answer: "Ogni file in uscita preserva tutta la formattazione, le immagini e la qualità del testo del documento di origine. Lo strumento si limita a dividere il contenuto in file più piccoli per rispettare il limite di dimensione; non comprime né degrada in alcun modo le pagine." },
    { question: "È sicuro suddividere documenti riservati per dimensione?", answer: "Sì. L'intera suddivisione avviene nel tuo browser, sul tuo dispositivo, quindi il tuo PDF non viene mai caricato da nessuna parte. Anche i documenti grandi o sensibili restano privati, il che è rassicurante quando prepari file da inviare via email o condividere." },
  ],
  "split-by-bookmarks": [
    { question: "Come decide lo strumento Dividi per Segnalibri dove suddividere il mio PDF?", answer: "Lo strumento legge la struttura dei segnalibri o dei capitoli già presenti nel tuo PDF e suddivide in quei punti, trasformando ogni sezione di segnalibro in un file separato. Scegli a quale livello di segnalibro suddividere, così le divisioni corrispondono alla struttura del tuo documento." },
    { question: "Posso scegliere a quale livello di segnalibro suddividere?", answer: "Sì. Lo strumento rileva tutti i segnalibri e ti permette di selezionare il livello, che si tratti dei capitoli di primo livello, delle sottosezioni o di un annidamento più profondo. Questa flessibilità ti consente di suddividere un documento in pochi capitoli grandi o in molte parti più piccole." },
    { question: "Cosa succede se il mio PDF non ha segnalibri?", answer: "Questo strumento si basa su una struttura di segnalibri esistente per determinare i punti di suddivisione, quindi funziona al meglio con PDF che hanno già capitoli o una struttura, come manuali, libri di testo o documenti legali. Senza segnalibri non ci sono riferimenti su cui suddividere." },
    { question: "I segnalibri vengono mantenuti nei file risultanti?", answer: "Sì. Ogni file suddiviso preserva i segnalibri al suo interno, insieme a tutta la formattazione, le immagini e la qualità del testo dell'originale. I capitoli restano navigabili, così la tua struttura organizzata viene trasferita nei documenti più piccoli." },
    { question: "I miei file restano privati durante la suddivisione per segnalibri?", answer: "Assolutamente. Tutta l'elaborazione avviene localmente nel tuo browser, quindi il tuo PDF non viene mai inviato a un server. I tuoi documenti strutturati restano sul tuo dispositivo e puoi scaricare i file suddivisi singolarmente o in un unico archivio ZIP." },
  ],
  "sign": [
    { question: "Come posso aggiungere la mia firma a un PDF?", answer: "Hai tre opzioni: disegnare la tua firma con il mouse o il touchpad, digitare il tuo nome scegliendo tra vari font, oppure caricare un'immagine della tua firma esistente. Poi la posizioni dove vuoi su qualsiasi pagina e scarichi il PDF firmato." },
    { question: "Posso posizionare e ridimensionare la mia firma sulla pagina?", answer: "Sì. Lo strumento offre un posizionamento flessibile, permettendoti di trascinare la firma in qualsiasi punto di qualsiasi pagina e di ridimensionarla per adattarla. È utile per le righe della firma, le sigle o per inserire ordinatamente il tuo segno in un campo di un modulo." },
    { question: "La firma viene davvero incorporata nel documento?", answer: "Sì. La tua firma viene incorporata direttamente nel PDF, diventando parte del documento stesso anziché un livello sovrapposto separato. Il file firmato mantiene un'alta qualità ed è pronto per essere scaricato e condiviso subito dopo la firma." },
    { question: "Firmare i PDF qui è gratuito e privato?", answer: "È gratuito, senza registrazione e completamente privato. Tutta l'elaborazione avviene localmente nel tuo browser, quindi i dati della firma e il documento non lasciano mai il tuo dispositivo. Questo lo rende adatto a firmare contratti o moduli a distanza senza stampare." },
    { question: "Posso firmare un PDF dal telefono o dal tablet?", answer: "Sì. Poiché funziona nel browser, puoi disegnare la tua firma direttamente con il touchscreen su cellulare o tablet, oppure digitarla o caricarla. Funziona senza installare alcuna app né stampare il documento." },
  ],
  "redact": [
    { question: "L'oscuramento con questo strumento è permanente?", answer: "Sì. Lo strumento oscura completamente le informazioni selezionate e le rimuove in modo che non possano essere recuperate o estratte dal documento in seguito. Questa rimozione irreversibile è ciò che lo rende sicuro per condividere file sensibili." },
    { question: "Cosa posso oscurare nel mio PDF?", answer: "Puoi selezionare aree o testi specifici da oscurare, ottenendo un controllo preciso su ciò che viene rimosso. Oscura singole parole, immagini o intere sezioni: è ideale per documenti legali, cartelle cliniche, estratti finanziari e qualsiasi cosa contenga informazioni personali." },
    { question: "In cosa differisce dal semplice disegnare un rettangolo nero sul testo?", answer: "A differenza di una semplice sovrapposizione, questo strumento rimuove in modo permanente le informazioni sottostanti invece di nasconderle solo visivamente. Con un rettangolo disegnato, il testo nascosto può comunque essere copiato; qui il contenuto sensibile viene davvero eliminato e reso irrecuperabile." },
    { question: "L'oscuramento riduce la qualità del resto del documento?", answer: "No. Vengono rimosse solo le aree oscurate. Tutto il contenuto visibile mantiene la qualità, la formattazione e la risoluzione originali. Puoi scaricare subito il PDF oscurato, pronto da condividere con le parti sensibili cancellate in modo permanente." },
    { question: "I miei file sono sicuri durante l'oscuramento?", answer: "Sì. Ogni passaggio avviene localmente nel tuo browser, quindi il tuo documento non viene mai caricato su alcun server. I file legali, medici o finanziari sensibili restano interamente sul tuo dispositivo durante tutto il processo di oscuramento, garantendo la massima privacy." },
  ],
  "remove-hidden-data": [
    { question: "Cosa rimuove esattamente Sanitizza PDF dal mio file?", answer: "Elimina le informazioni sull'autore, le date di creazione e modifica, i dettagli del software, i commenti, le annotazioni, i dati dei campi modulo, il JavaScript, i file incorporati e altri contenuti nascosti. Tutto ciò che vedi nella pagina rimane, mentre i metadati e gli script invisibili vengono ripuliti." },
    { question: "La sanitizzazione cambierà l'aspetto del mio documento?", answer: "No. Il processo preserva esattamente tutti i contenuti visibili, il testo, le immagini e la formattazione così come appaiono. Vengono rimossi solo i dati nascosti e potenzialmente sensibili, quindi il PDF ripulito appare identico ma non contiene alcun metadato sottostante." },
    { question: "Perché dovrei sanitizzare un PDF prima di condividerlo?", answer: "I metadati nascosti possono rivelare il tuo nome, il software che hai usato, la cronologia delle modifiche o script incorporati a chiunque apra il file. La sanitizzazione previene questa fuga di informazioni, cosa importante quando pubblichi documenti o li invii a terze parti." },
    { question: "Rimuove anche il JavaScript e i file incorporati?", answer: "Sì. Oltre ai metadati, lo strumento rimuove il JavaScript incorporato, i file allegati e altri contenuti potenzialmente non sicuri, rendendo il PDF risultante più pulito e sicuro da distribuire, non solo privato dei dettagli sull'autore." },
    { question: "Il processo di sanitizzazione è privato?", answer: "Completamente. Tutta la pulizia avviene localmente nel tuo browser, quindi il tuo documento non lascia mai il tuo dispositivo. Questo è particolarmente appropriato per uno strumento dedicato alla privacy, poiché il tuo file non viene caricato da nessuna parte mentre i suoi dati nascosti vengono rimossi." },
  ],
  "certificate": [
    { question: "Quali formati di certificato supporta Firma con Certificato?", answer: "Funziona con i certificati digitali standard X.509 nei formati .pfx e .p12. Puoi anche aggiungere dettagli come il motivo della firma e la tua posizione, che vengono incorporati insieme alla firma crittografica nel documento." },
    { question: "In cosa differisce la firma con certificato da una firma normale?", answer: "Una firma visiva mostra solo un grafico, mentre un certificato fornisce una prova crittografica dell'identità e dell'integrità del documento. Crea un sigillo a prova di manomissione che rivela se il file è stato alterato dopo la firma, rendendolo legalmente vincolante in molte giurisdizioni." },
    { question: "La firma rivelerà se qualcuno modifica il documento in seguito?", answer: "Sì. La firma con certificato incorpora nel PDF un sigillo a prova di manomissione. Se il documento viene modificato dopo la firma, la firma diventa non valida, avvisando i destinatari che l'integrità del file è stata compromessa dopo la tua firma." },
    { question: "Il mio certificato e la mia chiave privata sono al sicuro con questo strumento?", answer: "Sì. Tutta la firma avviene localmente nel tuo browser, quindi il tuo certificato e le chiavi private non lasciano mai il tuo dispositivo né vengono caricati su alcun server. Questo mantiene protette le tue credenziali sensibili mentre applichi una firma verificata." },
    { question: "Chi dovrebbe usare la firma basata su certificato?", answer: "È adatta a chiunque abbia bisogno di firme verificate e legalmente solide, come i professionisti legali che firmano contratti, i dipendenti pubblici che gestiscono documenti ufficiali o le aziende che approvano moduli dove è richiesta una prova crittografica dell'identità e dell'integrità del documento." },
  ],
  "pdf-to-images": [
    { question: "In quali formati immagine posso esportare le pagine del PDF?", answer: "Puoi scegliere PNG, JPEG o WebP. PNG mantiene una qualità perfetta e supporta la trasparenza, JPEG produce file più piccoli con buona qualità e WebP offre una compressione moderna con un eccellente rapporto qualità-dimensione per il web." },
    { question: "Posso convertire solo alcune pagine invece dell'intero PDF?", answer: "Sì. Puoi selezionare pagine specifiche da convertire oppure elaborare l'intero documento in una volta. Ogni pagina diventa un file immagine separato, utile per estrarre un singolo grafico o generare miniature." },
    { question: "Le immagini convertite manterranno la qualità originale?", answer: "Ogni pagina viene renderizzata alla sua risoluzione originale, preservando testo, immagini, grafica e layout. Scegliere PNG offre una qualità senza perdite con la trasparenza, così le immagini esportate riproducono fedelmente l'aspetto di ogni pagina nel PDF di origine." },
    { question: "Come faccio a scaricare più immagini convertite?", answer: "Dopo la conversione puoi salvare ogni immagine singolarmente oppure scaricarle tutte insieme in un unico archivio ZIP. L'opzione ZIP è comoda quando hai convertito molte pagine e vuoi raggrupparle in un solo file." },
    { question: "I miei PDF sono privati durante la conversione in immagini?", answer: "Sì. L'intera conversione avviene localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su un server. Il tuo documento resta sul tuo dispositivo mentre ogni pagina viene trasformata in un'immagine PNG, JPEG o WebP." },
  ],
  "images-to-pdf": [
    { question: "Quali formati di immagine posso combinare in un PDF?", answer: "Puoi trascinare file PNG, JPEG, WebP, GIF e BMP e mescolare liberamente i formati in un unico documento. Le immagini WebP vengono gestite automaticamente in background e ogni immagine che aggiungi diventa una pagina a sé nel PDF finito." },
    { question: "Come imposto l'ordine delle immagini nel mio PDF?", answer: "Dopo il caricamento, ti basta trascinare le miniature per disporle come preferisci prima di generare il file. Le pagine compaiono esattamente in quell'ordine, il che rende facile creare album fotografici o assemblare correttamente documenti scansionati." },
    { question: "Posso scegliere il formato e l'orientamento della pagina?", answer: "Sì. Scegli A4, Letter, A3, A5 o un formato personalizzato, imposta verticale o orizzontale, aggiungi margini e decidi se ogni immagine deve adattarsi alla pagina o se la pagina deve adattarsi all'immagine. Queste opzioni ti permettono di personalizzare il layout in base alle tue esigenze." },
    { question: "Le mie immagini vengono caricate su un server?", answer: "No. Tutto avviene localmente nel tuo browser, sfruttando l'elaborazione del tuo dispositivo, quindi le tue foto e scansioni non lasciano mai il tuo computer. Non ci sono caricamenti né account, il che mantiene le immagini personali o sensibili completamente private." },
    { question: "La conversione riduce la qualità delle mie immagini?", answer: "Le tue immagini mantengono la risoluzione e i colori originali quando vengono inserite nel PDF. Se attivi l'adattamento alla pagina, le immagini grandi vengono ridimensionate per stare ordinatamente nella pagina, ma non vengono mai ingrandite, così nitidezza e dettaglio restano intatti nel documento finale." },
  ],
  "pdf-to-word": [
    { question: "Il convertitore mantiene la mia formattazione in Word?", answer: "Ricostruisce il documento rilevando righe e paragrafi e riporta dimensioni dei caratteri e grassetto dove possibile. Tra le pagine vengono aggiunte interruzioni di pagina, così il DOCX modificabile resta vicino nella struttura al layout originale del PDF." },
    { question: "Funziona con un PDF scansionato?", answer: "I PDF scansionati o composti solo da immagini non contengono testo selezionabile da estrarre, quindi lo strumento non riesce a recuperare le parole poiché non esegue l'OCR. Funziona al meglio con PDF che già contengono testo reale e leggibile dalla macchina, anziché immagini di testo." },
    { question: "Posso convertire solo determinate pagine?", answer: "Sì. Inserisci un intervallo di pagine come 1-5 oppure una combinazione come 1,3,7-9, e solo quelle pagine vengono trasformate nel file Word. Lascialo vuoto o digita all per convertire l'intero documento in una sola volta." },
    { question: "La conversione da PDF a Word è gratuita e privata?", answer: "È completamente gratuita senza registrazione e la conversione avviene interamente all'interno del tuo browser. Il tuo PDF non viene mai inviato a un server, il che significa che contratti riservati, report o documenti personali restano sul tuo dispositivo." },
    { question: "Quale file produce e posso aprirlo ovunque?", answer: "Ottieni un file .docx standard che si apre in Microsoft Word, Google Docs, LibreOffice e nella maggior parte degli altri elaboratori di testo. Una volta scaricato, puoi modificare, riformattare e riutilizzare il testo proprio come qualsiasi normale documento Word." },
  ],
  "pdf-to-excel": [
    { question: "Come rileva le tabelle nel mio PDF?", answer: "Lo strumento analizza la posizione di ogni elemento di testo, raggruppando in righe gli elementi sulla stessa linea e allineando in colonne le posizioni orizzontali condivise. Quando trova una griglia chiara crea un vero foglio di calcolo; in caso contrario, ripiega su righe riga per riga." },
    { question: "Le pagine multiple vengono messe in un solo foglio o in più fogli?", answer: "Ogni pagina del PDF diventa una scheda di foglio di lavoro a sé nella cartella, etichettata con il numero di pagina, e le colonne vengono dimensionate automaticamente per la leggibilità. Questo mantiene separati e facili da navigare in Excel i dati provenienti da pagine diverse." },
    { question: "Può estrarre tabelle da una fattura o un report scansionato?", answer: "Solo se il PDF contiene testo reale. I documenti scansionati sono immagini e questo strumento non esegue l'OCR, quindi non può leggere i numeri dalla foto di una pagina. Usa PDF con testo realmente selezionabile per un'estrazione accurata." },
    { question: "Quale formato ottengo e lo strumento è gratuito?", answer: "Ricevi un file .xlsx pronto all'uso che si apre in Excel, Google Sheets o LibreOffice Calc, e lo strumento è completamente gratuito senza alcun account richiesto. Da lì puoi modificare, ordinare ed eseguire formule sui dati." },
    { question: "I miei dati finanziari sono al sicuro durante la conversione?", answer: "Assolutamente. Tutta l'estrazione delle tabelle avviene localmente nel tuo browser, quindi fatture, estratti conto e report finanziari non vengono mai caricati da nessuna parte. I tuoi numeri sensibili restano sul tuo dispositivo, dall'inizio fino al foglio di calcolo finito." },
  ],
  "pdf-to-text": [
    { question: "Il testo estratto mantiene l'ordine di lettura originale?", answer: "Sì. Lo strumento ordina il testo per posizione verticale e orizzontale, così le righe escono dall'alto verso il basso e da sinistra a destra, rispecchiando il modo in cui leggeresti la pagina. Il risultato è un file .txt pulito senza codici di formattazione o caratteri spuri." },
    { question: "Posso estrarre il testo solo da alcune pagine?", answer: "Puoi specificare un intervallo di pagine come 2-6 oppure un elenco come 1,4,9 per estrarre il testo solo da quelle pagine. C'è anche un'opzione per etichettare ogni pagina con il suo numero nell'output, se desideri marcatori di pagina chiari." },
    { question: "Riesce a estrarre il testo da un documento scansionato?", answer: "I PDF scansionati sono immagini di testo, e questo estrattore legge il testo incorporato anziché eseguire l'OCR, quindi non può riconoscere le parole all'interno di un'immagine. Dà il meglio con i PDF digitali che già contengono testo reale e selezionabile." },
    { question: "Lo strumento è gratuito e carica il mio PDF?", answer: "È gratuito senza registrazione e non viene caricato nulla. L'estrazione avviene direttamente nel tuo browser, sul tuo dispositivo, quindi anche ricerche riservate o documenti privati non viaggiano mai verso alcun server." },
    { question: "Cosa posso fare con il testo semplice in seguito?", answer: "L'output .txt pulito è ideale per l'analisi del testo, l'indicizzazione per la ricerca, la copia di contenuti in altre app o l'inserimento in script e altri strumenti di elaborazione. Poiché è testo semplice UTF-8, funziona praticamente con qualsiasi editor o programma." },
  ],
  "pdf-to-csv": [
    { question: "Posso cambiare il delimitatore o il carattere di virgolettatura nel CSV?", answer: "Sì. Puoi impostare un delimitatore personalizzato, ad esempio un punto e virgola al posto della virgola, e scegliere il carattere di virgolettatura usato per racchiudere i valori. I campi che contengono delimitatori, virgolette o interruzioni di riga vengono gestiti con escape automaticamente, così il CSV si importa senza problemi." },
    { question: "Crea un solo CSV o un file separato per ogni pagina?", answer: "Decidi tu. Per impostazione predefinita tutte le pagine vengono combinate in un unico CSV con marcatori di pagina, oppure puoi attivare file separati per ogni pagina. Quando ci sono più file, vengono raggruppati insieme in uno ZIP per un unico download." },
    { question: "Quanto bene gestisce le tabelle a più colonne?", answer: "Lo strumento mappa la posizione di ogni elemento di testo per rilevare righe e colonne, poi allinea le celle in una griglia strutturata. Funziona al meglio con tabelle ben impostate; le pagine con formattazione approssimativa possono ripiegare su un output più semplice, riga per riga." },
    { question: "Funziona con una tabella di un PDF scansionato?", answer: "No, perché le pagine scansionate sono immagini e lo strumento legge il testo incorporato senza OCR. Per un output CSV affidabile, usa PDF che contengono testo realmente selezionabile, anziché tabelle fotografate o scansionate." },
    { question: "È gratuito e i miei dati restano privati?", answer: "Il convertitore è gratuito senza account, e tutta l'elaborazione resta all'interno del tuo browser, sul tuo dispositivo. I tuoi dati tabellari non vengono mai caricati, quindi le tabelle finanziarie o di ricerca restano riservate mentre le trasformi in CSV." },
  ],
  "pdf-to-html": [
    { question: "Posso includere immagini nell'output HTML?", answer: "C'è un'opzione per incorporare le immagini direttamente come dati base64, così l'HTML è autonomo e non dipende da file di immagine separati. Puoi anche lasciare fuori le immagini per ottenere una pagina più leggera e incentrata sul testo, quando questo si adatta meglio alle tue esigenze." },
    { question: "Posso applicare il mio CSS alla pagina convertita?", answer: "Sì. Puoi fornire stili CSS personalizzati per controllare l'aspetto dell'HTML generato, permettendoti di abbinarlo al design o alla formattazione del tuo sito. L'output si apre in qualsiasi browser e può essere perfezionato ulteriormente in qualsiasi editor HTML." },
    { question: "Quali pagine vengono convertite in HTML?", answer: "Per impostazione predefinita viene convertito l'intero documento, ma puoi inserire un intervallo di pagine come 1-4 o un elenco come 2,5,8 per trasformare in HTML solo le pagine selezionate. Questo è comodo quando ti serve online solo una parte di un PDF lungo." },
    { question: "La conversione è gratuita e resta sul mio dispositivo?", answer: "È gratuita senza registrazione e l'intera conversione avviene localmente nel tuo browser. Il tuo PDF non viene mai inviato da nessuna parte, quindi anche documenti non pubblicati o sensibili restano privati mentre li prepari per il web." },
    { question: "Cosa posso fare con il file HTML in seguito?", answer: "Il risultato è un file HTML pronto per il web che puoi pubblicare online, incorporare in un sito o aprire in qualsiasi browser. I caratteri speciali vengono gestiti correttamente con escape, così il markup è pulito e pronto per ulteriori modifiche nei tuoi strumenti." },
  ],
  "pdf-to-markdown": [
    { question: "Rileva automaticamente i titoli?", answer: "Sì. Il convertitore analizza il testo e può contrassegnare i probabili titoli con la sintassi dei titoli di Markdown, aiutando a preservare la gerarchia del documento. Questo rende l'output pronto da inserire in una documentazione o in un blog con la struttura intatta." },
    { question: "Come vengono gestiti i caratteri speciali nel Markdown?", answer: "I caratteri che hanno un significato in Markdown, come asterischi, trattini bassi, parentesi quadre e backtick, vengono gestiti con escape così da apparire come testo semplice invece di compromettere la formattazione. In questo modo il contenuto convertito viene visualizzato correttamente ovunque tu lo incolli." },
    { question: "Posso convertire in Markdown solo pagine specifiche?", answer: "Puoi inserire un intervallo di pagine come 1-3 o un elenco come 2,4,6 per convertire solo quelle pagine. Lasciando il campo vuoto o inserendo all si elabora l'intero documento in un unico file Markdown." },
    { question: "È gratuito e il mio PDF viene caricato da qualche parte?", answer: "Lo strumento è gratuito senza alcun account necessario, e la conversione avviene interamente nel tuo browser. Nulla viene caricato su un server, quindi documentazione tecnica o bozze che non sei pronto a condividere restano completamente sul tuo dispositivo." },
    { question: "Perché usare Markdown invece di un altro formato?", answer: "Markdown è testo semplice, quindi l'output è leggero, facile da modificare in qualsiasi editor e funziona senza problemi con i sistemi di controllo versione come Git. Questo lo rende ideale per documentazione, scrittura tecnica e post di blog." },
  ],
  "compress": [
    { question: "Di quanto può ridurre il mio PDF?", answer: "Il risparmio dipende dal contenuto del file e dal livello di qualità che scegli. Lo strumento ristruttura il PDF usando flussi di oggetti e può rimuovere i metadati, riducendo l'overhead. I documenti ricchi di immagini e appesantiti sono di solito quelli che ne traggono più beneficio." },
    { question: "La compressione sfoca il mio testo o le mie immagini?", answer: "Il testo resta nitido e ricercabile perché non viene rasterizzato. Scegli un livello di qualità da basso ad alto per bilanciare la dimensione del file rispetto alla fedeltà, così puoi privilegiare file più piccoli o preservare più dettagli a seconda del documento." },
    { question: "Posso rimuovere i metadati per rendere il file più piccolo e più pulito?", answer: "Sì. C'è un'opzione per rimuovere i metadati come titolo, autore e parole chiave, il che riduce leggermente le dimensioni ed elimina dettagli personali nascosti. È utile prima di condividere un documento che preferiresti non sia etichettato con le tue informazioni." },
    { question: "C'è un limite alla dimensione del file?", answer: "Non c'è un limite fisso lato server perché la compressione avviene localmente nel tuo browser. Il limite pratico dipende dalla memoria disponibile del tuo dispositivo, quindi i file molto grandi funzionano ma potrebbero richiedere più tempo su macchine meno potenti." },
    { question: "I miei documenti sono privati quando li comprimo?", answer: "Assolutamente. Nessun file viene caricato su alcun server; tutta l'ottimizzazione avviene sul tuo dispositivo. Questo lo rende sicuro per comprimere report o contratti riservati che devi inviare via email o archiviare senza esporli online." },
  ],
  "add-watermark": [
    { question: "Come faccio ad aggiungere una filigrana al mio PDF?", answer: "Carica il tuo PDF, poi scegli una filigrana di testo o di immagine e regolane posizione, opacità, rotazione, dimensione e colore. Puoi applicarla a ogni pagina oppure selezionarne alcune specifiche. Quando l'anteprima ti sembra giusta, scarica il file con filigrana direttamente dal browser." },
    { question: "Posso usare il logo della mia azienda come filigrana immagine?", answer: "Sì. Oltre alle filigrane di testo come Riservato o Bozza, puoi caricare un'immagine, ad esempio il logo della tua azienda, e sovrapporla alle pagine. Regola dimensione, opacità e rotazione in modo che il marchio resti discreto sullo sfondo oppure appaia deciso e in primo piano." },
    { question: "Posso applicare la filigrana solo ad alcune pagine invece che all'intero documento?", answer: "Assolutamente. Non sei costretto a marchiare tutto. Seleziona le pagine specifiche su cui applicare la filigrana lasciando intatte le altre, oppure applicala in modo uniforme a tutto il documento per un branding coerente su report, proposte e altri file multipagina." },
    { question: "L'aggiunta di una filigrana ridurrà la qualità del mio PDF?", answer: "No. La filigrana viene sovrapposta alle pagine mentre il testo, le immagini e la formattazione originali restano intatti al di sotto. Il PDF risultante mantiene la sua alta qualità e puoi controllare l'opacità in modo che il marchio protegga il tuo lavoro senza oscurarne il contenuto." },
    { question: "Lo strumento per le filigrane è gratuito e i miei documenti restano privati?", answer: "È completamente gratuito e non richiede registrazione. Ogni passaggio viene eseguito localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su alcun server. Contratti, proposte e file riservati restano interamente sul tuo dispositivo durante l'intero processo." },
  ],
  "page-numbers": [
    { question: "Come faccio ad aggiungere i numeri di pagina a un PDF?", answer: "Apri il tuo PDF, scegli dove devono comparire i numeri, poi scarica il risultato. Puoi posizionarli in alto o in basso e a sinistra, al centro o a destra, con il controllo su carattere, dimensione e numero iniziale per adattarsi allo stile del tuo documento." },
    { question: "Posso scegliere dove compaiono i numeri di pagina e da quale numero iniziare?", answer: "Sì. Decidi tu la posizione, in alto o in basso e allineata a sinistra, al centro o a destra, e puoi impostare un numero iniziale personalizzato. È utile quando le pagine preliminari o una copertina fanno sì che la pagina uno non debba essere la prima numerata." },
    { question: "Posso saltare la numerazione sulla copertina o su pagine specifiche?", answer: "Puoi farlo. Lo strumento ti permette di applicare la numerazione a tutto il documento o di saltare pagine selezionate come copertine o frontespizi, così solo le pagine che desideri riportano i numeri, il che è ideale per report e tesi." },
    { question: "Posso personalizzare il carattere e la dimensione dei numeri di pagina?", answer: "Certamente. Oltre al posizionamento, puoi regolare il carattere e la dimensione dei numeri in modo che si integrino con la tipografia del tuo documento, mantenendo articoli accademici, documenti legali e manuali stampati dall'aspetto coerente e professionale." },
    { question: "È gratuito e i miei file restano privati?", answer: "Aggiungere i numeri di pagina è gratuito e non serve un account. Tutta l'elaborazione avviene localmente all'interno del tuo browser, il che significa che il tuo PDF non viene mai inviato a un server. Le tue tesi, i contratti e i report restano riservati sul tuo computer." },
  ],
  "crop": [
    { question: "Come faccio a ritagliare le pagine di un PDF?", answer: "Carica il tuo PDF e imposta visivamente i bordi di ritaglio nell'interfaccia per eliminare margini o bordi. Applica lo stesso ritaglio a ogni pagina oppure regola le pagine singolarmente, poi scarica il documento ordinato quando ha l'aspetto desiderato." },
    { question: "Posso ritagliare ogni pagina in modo diverso o solo tutte le pagine allo stesso modo?", answer: "Sono disponibili entrambe le opzioni. Puoi applicare un ritaglio uniforme a tutto il documento per fare in fretta, oppure regolare con precisione le singole pagine quando le scansioni hanno margini irregolari, offrendoti flessibilità per materiale di origine misto o disomogeneo." },
    { question: "Il ritaglio rimuoverà testo o immagini all'interno delle mie pagine?", answer: "No. Il ritaglio elimina solo l'area al di fuori dei bordi scelti. Tutto il testo, le immagini e la formattazione all'interno della regione conservata vengono mantenuti esattamente, così rimuovi lo spazio bianco o i bordi neri dello scanner senza perdere contenuti essenziali." },
    { question: "Posso usare lo strumento di ritaglio per rimuovere i bordi neri dello scanner e i margini?", answer: "Sì, è uno degli usi principali. È ottimo per eliminare i bordi neri lasciati dagli scanner, ritagliare lo spazio bianco in eccesso attorno ai documenti scansionati e concentrare le pagine sul contenuto importante per una stampa più pulita e una lettura a schermo più agevole." },
    { question: "Il ritaglio è gratuito e i miei file vengono caricati da qualche parte?", answer: "Lo strumento di ritaglio è gratuito e non richiede registrazione. Non viene caricato nulla; l'intero processo viene eseguito localmente nel tuo browser, quindi libri scansionati, documenti privati e qualsiasi PDF riservato non lasciano mai il tuo dispositivo." },
  ],
  "resize": [
    { question: "Come faccio a cambiare la dimensione delle pagine di un PDF?", answer: "Carica il tuo PDF e scegli un preset come A4 o Letter, oppure inserisci larghezza e altezza personalizzate. Lo strumento ridimensiona il contenuto alle nuove dimensioni mantenendo le proporzioni, poi ti consente di scaricare il file ridimensionato." },
    { question: "A quali dimensioni e formati di pagina posso ridimensionare?", answer: "Puoi selezionare preset comuni come A4 e Letter, oppure specificare le tue dimensioni personalizzate. Questo rende facile convertire tra gli standard regionali della carta o adattare le pagine a uno specifico requisito di layout per la stampa o la condivisione." },
    { question: "Il ridimensionamento distorcerà o stirerà il mio contenuto?", answer: "No. Quando adatta le pagine alle nuove dimensioni, lo strumento conserva le proporzioni in modo che testo e immagini restino proporzionati e leggibili invece di essere stirati. Il risultato mantiene la sua qualità, pronto per le tipografie o i compiti standardizzati." },
    { question: "Posso uniformare un documento con dimensioni di pagina miste?", answer: "Sì. Se hai pagine scansionate di dimensioni diverse o un documento che mescola formati, puoi ridimensionarle tutte a un'unica dimensione coerente, il che è ideale prima di inviare i file a una tipografia o per unificare un PDF compilato." },
    { question: "Lo strumento di ridimensionamento è gratuito e privato?", answer: "È gratuito e senza registrazione. Tutto il ridimensionamento viene eseguito localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su alcun server. I tuoi documenti restano riservati sul tuo dispositivo dall'inizio alla fine." },
  ],
  "grayscale": [
    { question: "Come faccio a convertire un PDF in scala di grigi?", answer: "Basta caricare il tuo PDF a colori e lo strumento converte automaticamente ogni pagina in bianco e nero. Testo, immagini e grafiche colorate diventano sfumature uniformi di grigio e puoi scaricare subito il documento monocromatico finito." },
    { question: "La conversione in scala di grigi riduce la dimensione del file PDF?", answer: "Spesso sì. Rimuovere le informazioni sul colore da immagini e grafiche può ridurre il file, il che è utile per inviare via email, archiviare o caricare documenti. La conversione crea anche un aspetto più uniforme pur mantenendo i dettagli nitidi." },
    { question: "Il mio testo e le immagini resteranno nitidi dopo la conversione in scala di grigi?", answer: "Sì. Lo strumento converte i colori in sfumature uniformi di grigio preservando la nitidezza e il dettaglio di testo, immagini e grafiche, così il risultato resta pulito e leggibile invece di apparire slavato o sfocato." },
    { question: "La scala di grigi è utile per risparmiare sui costi di stampa?", answer: "Decisamente. Convertire in bianco e nero prima della stampa ti permette di evitare l'uso di inchiostro a colori su documenti lunghi, facendoti risparmiare. È una scelta diffusa per stampare report e dispense in modo economico o per archiviare i file in un formato monocromatico coerente." },
    { question: "Lo strumento per la scala di grigi è gratuito e i miei file sono al sicuro?", answer: "Convertire in scala di grigi è gratuito e non serve alcun account. Tutto avviene localmente nel tuo browser, quindi nessun file viene caricato su alcun server. I tuoi documenti restano completamente privati sul tuo dispositivo durante l'intero processo." },
  ],
  "invert-colors": [
    { question: "Come faccio a invertire i colori di un PDF per la modalità scura?", answer: "Carica il tuo PDF ed esegui l'inversione in un'unica operazione. Gli sfondi bianchi diventano scuri e il testo nero diventa chiaro su tutte le pagine, producendo all'istante una versione a tema scuro che puoi scaricare per una visualizzazione a schermo confortevole." },
    { question: "Il testo sarà ancora selezionabile dopo aver invertito i colori?", answer: "Sì. L'inversione capovolge i colori mantenendo il testo nitido, leggibile e completamente selezionabile, così il documento resta funzionale. Puoi ancora cercare, evidenziare e copiare il testo proprio come potevi fare prima della trasformazione." },
    { question: "Questo crea una vera esperienza di lettura in modalità scura?", answer: "Sì. Rendendo scuri gli sfondi bianchi e brillanti e chiaro il testo su di essi, produce un PDF a tema scuro confortevole che riduce l'affaticamento degli occhi durante le letture notturne o le lunghe sessioni a schermo in ambienti con poca luce." },
    { question: "Posso invertire i colori dell'intero documento in una volta sola?", answer: "Sì. Un'unica operazione applica l'inversione a ogni pagina dell'intero documento, quindi non c'è bisogno di regolare le pagine una per una. Ottieni un file completamente a tema scuro pronto per la visualizzazione a schermo in pochi secondi." },
    { question: "Invertire i colori è gratuito e i miei file restano privati?", answer: "Lo strumento è gratuito e non richiede registrazione. Tutta l'elaborazione viene eseguita localmente nel tuo browser, quindi il tuo PDF non viene mai caricato da nessuna parte. I tuoi materiali di studio e documenti restano riservati sul tuo dispositivo." },
  ],
  "flatten": [
    { question: "Come faccio ad appiattire un PDF?", answer: "Carica il tuo PDF e lo strumento unisce campi modulo, annotazioni ed elementi interattivi direttamente nel contenuto statico della pagina. Campi compilabili, caselle di controllo, commenti e marcature diventano parte della pagina e puoi scaricare immediatamente il file bloccato." },
    { question: "Cosa succede ai campi modulo che ho compilato quando appiattisco?", answer: "Vengono bloccati in modo permanente nella pagina. Dopo l'appiattimento, caselle di controllo, campi di testo e altri input diventano parte del contenuto statico, così i destinatari non possono modificare i dati. È ideale per finalizzare moduli completati prima di condividerli o per archiviare documenti firmati." },
    { question: "Perché dovrei appiattire un PDF prima di condividerlo?", answer: "L'appiattimento impedisce ai destinatari di alterare i dati compilati e garantisce che il documento venga visualizzato in modo coerente su ogni visualizzatore e stampante PDF. È perfetto per inviare moduli ufficiali o distribuire file pronti per la stampa e resistenti alle manomissioni, che devono apparire esattamente come previsto." },
    { question: "L'appiattimento blocca nella pagina anche commenti e annotazioni?", answer: "Sì. Oltre ai campi modulo, anche le annotazioni come commenti e marcature vengono unite al contenuto della pagina, così il risultato visibile viene conservato esattamente senza che rimangano livelli modificabili sopra il documento." },
    { question: "Lo strumento di appiattimento è gratuito e i miei dati sono al sicuro?", answer: "L'appiattimento è gratuito e non serve un account. Tutta l'elaborazione avviene localmente nel tuo browser, quindi i tuoi moduli completati e documenti firmati non vengono mai caricati su un server. I tuoi dati sensibili restano privati sul tuo dispositivo." },
  ],
  "remove-annotations": [
    { question: "Come faccio a rimuovere le annotazioni da un PDF?", answer: "Carica il tuo PDF e lo strumento rileva ed elimina ogni livello di annotazione su tutte le pagine in un'unica operazione. Commenti, evidenziazioni, note adesive e marcature vengono rimossi, lasciando un documento pulito che puoi scaricare subito." },
    { question: "Che tipi di marcature rimuove questo strumento?", answer: "Cancella commenti, evidenziazioni, note adesive e altre marcature aggiunte durante la revisione o la collaborazione. Ogni livello di annotazione viene rilevato e rimosso in una sola volta, producendo una versione raffinata e priva di distrazioni, libera dal disordine editoriale." },
    { question: "La rimozione delle annotazioni modificherà il testo o le immagini originali?", answer: "No. Vengono eliminati solo i livelli di annotazione. Il testo, le immagini e la formattazione sottostanti vengono conservati esattamente come appaiono, così ottieni una copia pulita senza alterare il contenuto effettivo del documento." },
    { question: "Posso cancellare tutte le note dei revisori in una volta prima di pubblicare?", answer: "Sì. Lo strumento rimuove ogni annotazione su tutte le pagine in un'unica operazione, rendendolo perfetto per cancellare i feedback dei revisori da una bozza finalizzata o per produrre una copia professionale e pulita di un manoscritto pieno di marcature." },
    { question: "Rimuovere le annotazioni è gratuito e i miei file restano privati?", answer: "Lo strumento è gratuito e senza registrazione. Tutta l'elaborazione viene eseguita localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su alcun server. I tuoi documenti revisionati e le bozze restano riservati sul tuo dispositivo." },
  ],
  "extract-images": [
    { question: "Come si estraggono le immagini da un PDF con questo strumento?", answer: "Carica il tuo PDF: lo strumento analizza ogni pagina alla ricerca di immagini incorporate e le estrae automaticamente. Puoi estrarle da tutte le pagine oppure specificare un intervallo di pagine, per poi scaricare i risultati. Il processo non richiede alcuna selezione manuale o screenshot." },
    { question: "In quali formati posso salvare le immagini estratte?", answer: "Puoi esportare le immagini estratte come file PNG o JPEG. Il formato PNG mantiene una qualità senza perdite, mentre il JPEG ti permette di impostare un livello di compressione per ottenere file più piccoli. Scegli il formato più adatto al modo in cui intendi riutilizzare le immagini in seguito." },
    { question: "Posso scaricare tutte le immagini estratte in una sola volta?", answer: "Sì. Quando un PDF contiene più immagini, lo strumento le raggruppa in un unico archivio ZIP, così puoi scaricare tutto con un solo clic. Ogni file viene nominato in base alla pagina di origine, mantenendo le immagini estratte ordinate e facili da consultare in seguito." },
    { question: "Le immagini estratte conservano la loro qualità originale?", answer: "Lo strumento estrae le immagini raster incorporate mantenendo una risoluzione vicina a quella di archiviazione, così foto e grafica restano nitide. Scegliendo il PNG le mantieni senza perdite, mentre la qualità del JPEG è regolabile. Tieni presente che le illustrazioni puramente vettoriali non sono immagini in pixel e potrebbero non essere estratte come file separati." },
    { question: "I miei file PDF vengono caricati da qualche parte quando estraggo le immagini?", answer: "No. Tutta l'estrazione avviene localmente nel tuo browser, utilizzando le risorse del tuo dispositivo. Il tuo PDF non viene mai inviato a un server, quindi report riservati, contratti o documenti personali restano completamente privati durante tutto il processo. Lo strumento è inoltre gratuito." },
  ],
  "remove-images": [
    { question: "La rimozione delle immagini cancella il testo del mio PDF?", answer: "No. Lo strumento elimina gli oggetti immagine incorporati lasciando intatti il testo, la grafica vettoriale e l'impaginazione. Il contenuto scritto resta perfettamente leggibile e ricercabile, così ottieni un documento pulito e incentrato sul testo, anziché un file danneggiato o privo di elementi." },
    { question: "La rimozione delle immagini rende il mio file PDF più piccolo?", answer: "Di solito sì, e spesso in modo drastico. Le immagini sono in genere la parte più pesante di un PDF, quindi rimuoverle può ridurre notevolmente un report voluminoso. In questo modo il documento diventa molto più facile da inviare via email, da caricare su portali con limiti di dimensione o da archiviare senza occupare spazio." },
    { question: "Lo strumento rimuove le immagini da tutte le pagine in una sola volta?", answer: "Sì. In un'unica operazione analizza tutte le pagine e rimuove gli XObject immagine incorporati, le immagini inline e gli operatori che le disegnano. Non devi procedere pagina per pagina: l'intero documento viene elaborato insieme in un solo passaggio, per un risultato uniforme." },
    { question: "Questo strumento è gratuito e devo creare un account?", answer: "È completamente gratuito, senza registrazione, login o filigrane. Basta aprire lo strumento, trascinare il tuo PDF e scaricare la versione priva di immagini. Non ci sono limiti di utilizzo né paywall nascosti che bloccano il risultato al termine dell'elaborazione." },
    { question: "I miei documenti sono al sicuro quando rimuovo le immagini?", answer: "Tutto avviene localmente nel tuo browser, quindi il tuo PDF non viene mai caricato su alcun server. I file riservati restano sul tuo dispositivo dall'inizio alla fine, il che rende lo strumento ideale per contratti sensibili, report finanziari e documenti privati." },
  ],
  "optimize-images": [
    { question: "Come fa questo strumento a ridurre le dimensioni del mio PDF?", answer: "Individua le immagini incorporate nel tuo PDF, riduce la risoluzione di quelle più grandi del necessario e le ricomprime con impostazioni efficienti. Poiché le immagini sono di solito la parte più pesante di un documento, questo produce in genere un file molto più piccolo mantenendo le pagine nitide." },
    { question: "Posso controllare la qualità e la risoluzione delle immagini?", answer: "Sì. Puoi impostare un livello di compressione JPEG e una risoluzione massima per il lato più lungo di ogni immagine. Impostazioni più basse riducono il file in modo più aggressivo, mentre quelle più alte preservano più dettagli, permettendoti di bilanciare le dimensioni con la nitidezza visiva." },
    { question: "L'ottimizzazione rovina le immagini trasparenti o i loghi?", answer: "No. Lo strumento rileva le immagini con trasparenza e le ricodifica come PNG per preservare il canale alfa, mentre le foto opache vengono compresse in JPEG per il massimo risparmio. I loghi e le sovrapposizioni trasparenti mantengono le loro aree trasparenti intatte, senza acquisire uno sfondo pieno." },
    { question: "Cosa succede ai formati di immagine che lo strumento non può elaborare?", answer: "Alcuni formati specializzati, come determinati stream CMYK, JBIG2 o JPEG2000, non possono essere ricodificati nel browser. Lo strumento si limita a saltare quelle immagini e continua a ottimizzare le altre, così l'operazione si completa con successo invece di bloccarsi su un'immagine non supportata." },
    { question: "L'ottimizzazione avviene in modo privato nel mio browser?", answer: "Sì. Tutta la riduzione della risoluzione e la compressione avvengono localmente sul tuo dispositivo e nulla viene caricato su un server. Il tuo PDF resta privato, il che è ideale per ridurre report o presentazioni riservate prima di inviarli via email, il tutto in modo completamente gratuito." },
  ],
  "add-qr-code": [
    { question: "Cosa posso codificare nel codice QR che aggiungo?", answer: "Puoi codificare qualsiasi URL di un sito web o testo semplice, come un recapito, un messaggio promozionale o un link per il download. Una volta scansionato, il codice apre il link o mostra il tuo testo. È utile per volantini, brochure, fatture e biglietti per eventi." },
    { question: "Posso scegliere dove appare il codice QR nella pagina?", answer: "Sì. Imposti sia la posizione che la dimensione del codice QR, così si trova esattamente dove desideri. Puoi anche scegliere una pagina specifica o un intervallo di pagine, invece di applicarlo all'intero documento." },
    { question: "Il codice QR si scansionerà in modo affidabile una volta stampato?", answer: "Sì. Il codice viene generato in modo nitido a un'alta risoluzione in pixel con correzione degli errori integrata, così resta scansionabile sia da schermi che da carta. Mantenerlo a una dimensione ragionevole nella pagina aiuta le fotocamere a riconoscerlo rapidamente." },
    { question: "Come aggiungo un codice QR al mio PDF?", answer: "Carica il tuo PDF, digita l'URL o il testo che vuoi codificare, quindi posiziona e dimensiona il codice sulla pagina scelta. Lo strumento lo genera e lo inserisce all'istante, e scarichi subito il PDF finito." },
    { question: "Il mio PDF resta privato quando aggiungo un codice QR?", answer: "Assolutamente sì. Il codice QR viene generato e incorporato interamente nel tuo browser, senza che alcun file lasci mai il tuo dispositivo. In questo modo fatture, biglietti e documenti interni restano riservati, e lo strumento è gratuito senza necessità di registrazione." },
  ],
  "add-barcode": [
    { question: "Quali formati di codice a barre supporta questo strumento?", answer: "Puoi generare Code128, Code39, EAN-13, UPC-A, ITF-14 e persino codici QR. I formati lineari sono adatti all'etichettatura per la vendita al dettaglio e la gestione del magazzino, mentre il QR funziona per link o dati più lunghi. Basta scegliere la simbologia adatta al tuo scanner o flusso di lavoro." },
    { question: "Lo strumento verifica che i dati del mio codice a barre siano validi?", answer: "Sì. I formati numerici vengono convalidati prima della generazione: EAN-13 richiede 12 o 13 cifre, UPC-A ne richiede 11 o 12 e ITF-14 ne richiede 13 o 14. Se i dati non rientrano nel formato scelto, riceverai un errore invece di un codice non scansionabile." },
    { question: "Posso posizionare il codice a barre esattamente dove mi serve nella pagina?", answer: "Controlli la posizione, la larghezza e l'altezza del codice a barre, e puoi applicarlo a una pagina specifica o a un intervallo di pagine. Questo permette al codice di allinearsi perfettamente al layout della tua etichetta, al cartellino del prezzo o al foglio di spedizione, invece di finire in un punto fisso." },
    { question: "Il codice a barre verrà scansionato correttamente alla cassa o in magazzino?", answer: "Sì. Ogni codice a barre viene generato a una risoluzione nitida e pronta per la stampa, con il valore leggibile mostrato al di sotto. Questo output preciso è pensato per una scansione affidabile sia su schermi che su etichette stampate, alle casse e nelle operazioni logistiche." },
    { question: "Aggiungere un codice a barre è gratuito e privato?", answer: "È gratuito senza necessità di account, e il codice a barre viene creato direttamente nel tuo browser. Il tuo PDF e i dati dei prodotti non toccano mai un server, così fogli di inventario e cataloghi restano riservati mentre produci documenti scansionabili internamente." },
  ],
  "add-bookmarks": [
    { question: "In che modo i segnalibri aiutano i lettori a navigare nel mio PDF?", answer: "I segnalibri creano un sommario cliccabile che appare nella barra laterale dei lettori PDF standard. I lettori cliccano su una voce per saltare direttamente a quella pagina, rendendo report lunghi, ebook e manuali molto più facili da consultare rispetto allo scorrimento pagina per pagina." },
    { question: "Posso creare segnalibri annidati o a più livelli?", answer: "Sì. Lo strumento supporta segnalibri gerarchici, così puoi annidare sotto-voci all'interno dei capitoli principali per costruire un sommario strutturato. Ogni segnalibro punta a una pagina specifica, conferendo al tuo documento un albero di navigazione pulito e ordinato nel pannello del lettore." },
    { question: "Posso modificare o sostituire i segnalibri già esistenti?", answer: "Puoi aggiungere nuove voci e ricostruire il sommario del documento. Per impostazione predefinita lo strumento sostituisce il sommario esistente con la struttura che definisci, permettendoti di riorganizzare un insieme di segnalibri disordinato o obsoleto in uno nuovo e accurato per i tuoi lettori." },
    { question: "Dove appaiono i segnalibri dopo averli aggiunti?", answer: "Appaiono nella barra laterale dei segnalibri o del sommario di qualsiasi visualizzatore PDF standard, inclusi Acrobat, Anteprima e la maggior parte dei browser. I lettori aprono quel pannello per vedere il tuo sommario completo e cliccare istantaneamente su qualsiasi sezione." },
    { question: "I miei file sono privati quando aggiungo i segnalibri?", answer: "Sì. Il sommario viene scritto nel tuo PDF localmente nel tuo browser, senza alcun caricamento su un server. Il tuo documento resta sul tuo dispositivo per tutto il tempo, e lo strumento è gratuito, senza registrazione né filigrane." },
  ],
  "add-hyperlinks": [
    { question: "Che tipi di link posso aggiungere al mio PDF?", answer: "Puoi aggiungere link web cliccabili usando indirizzi http o https, così come link mailto per gli indirizzi email. I domini semplici come example.com vengono automaticamente convertiti in un URL https completo, così i lettori possono toccare direttamente citazioni, riferimenti o recapiti." },
    { question: "Posso mostrare un testo visibile del link sopra l'area collegata?", answer: "Sì. Ogni link può includere un'etichetta opzionale che viene disegnata in blu all'interno del rettangolo del link, così l'area cliccabile è chiaramente visibile. Se ometti l'etichetta, il link funziona comunque come una regione cliccabile invisibile sovrapposta al contenuto esistente." },
    { question: "Come posiziono un collegamento ipertestuale nella pagina?", answer: "Definisci un'area rettangolare su una pagina specifica in cui collocare il link, impostandone la posizione e la dimensione su quella pagina. Questo ti permette di posizionare una zona cliccabile con precisione sopra una parola, una citazione o una regione, invece che sull'intera pagina." },
    { question: "I link resteranno cliccabili in altri visualizzatori PDF?", answer: "Sì. Lo strumento aggiunge annotazioni di link standard, così i link restano pienamente interattivi nei lettori più comuni come Acrobat, Anteprima e la maggior parte dei browser. I destinatari possono cliccarci sopra per aprire la pagina web di destinazione o avviare un'email senza passaggi aggiuntivi." },
    { question: "Il mio PDF viene caricato quando aggiungo collegamenti ipertestuali?", answer: "No. I link vengono incorporati localmente nel tuo browser e il tuo file non lascia mai il tuo dispositivo. In questo modo report e brochure ricchi di riferimenti restano privati, e lo strumento è completamente gratuito, senza account né filigrane sul documento finito." },
  ],
  "add-attachments": [
    { question: "Che tipi di file posso incorporare in un PDF?", answer: "Puoi incorporare più file di tipi diversi, come fogli di calcolo, immagini, documenti e file di dati grezzi. Viaggiano all'interno del PDF come un unico pacchetto, il che mantiene insieme i materiali correlati così nulla si separa quando condividi il documento." },
    { question: "Dove appaiono gli allegati incorporati per il destinatario?", answer: "Vengono archiviati nel pannello degli allegati del PDF, accessibile nei lettori standard come Acrobat che supportano i file incorporati. I destinatari aprono quel pannello per visualizzare o salvare ogni file allegato. Le pagine visibili del tuo documento restano invariate dall'incorporamento." },
    { question: "L'incorporamento dei file cambia l'aspetto delle pagine del mio PDF?", answer: "No. Gli allegati vengono aggiunti alla struttura interna dei file del documento, non disegnati sulle pagine, quindi il layout, il testo e la formattazione restano esattamente come erano. I file aggiuntivi viaggiano in silenzio senza alterare nulla di ciò che i lettori vedono sullo schermo." },
    { question: "Perché dovrei incorporare i file invece di inviarli separatamente?", answer: "Raggruppare tutto in un unico PDF mantiene i materiali correlati organizzati e garantisce che i file di supporto non vadano persi durante l'invio. È utile per abbinare un foglio di calcolo a un report finanziario, allegare prove a un atto legale o inviare i dati di origine insieme a un articolo di ricerca." },
    { question: "È gratuito e i miei file restano privati?", answer: "Sì a entrambe le domande. L'incorporamento avviene localmente nel tuo browser senza alcun caricamento su un server, così fascicoli e set di dati riservati restano sul tuo dispositivo. Lo strumento è gratuito, senza registrazione, login o filigrane." },
  ],
};
